SELECT email
FROM alumni
WHERE alum_id IN (SELECT alum_id FROM donations);

SELECT alum_id, inclination_score
FROM engagement_scores
WHERE events_attended > 50;

SELECT COUNT(alum_id)
FROM engagement_scores
WHERE events_attended > 50;

SELECT AVG(lifetime_donation) AS average_donation
FROM alumni
WHERE lifetime_donation > 10000;

SELECT rfm
FROM alumni
ORDER BY rfm DESC;
